import React, { useState } from "react";
import axios from "axios";

const AudioUpload = () => {
  const [audioFile, setAudioFile] = useState(null);
  const [uploadedFilePath, setUploadedFilePath] = useState("");
  const [downloads, setDownloads] = useState([]);

  const handleFileChange = (e) => {
    setAudioFile(e.target.files[0]);
  };

  const handleUpload = async () => {
    if (!audioFile) return alert("Please select an audio file!");

    const formData = new FormData();
    formData.append("audio", audioFile);

    try {
      const response = await axios.post("http://localhost:5001/upload", formData);
      setUploadedFilePath(response.data.filePath);
      setDownloads([]); // Reset downloads for new upload
      alert("File uploaded successfully!");
    } catch (err) {
      console.error("Error uploading file:", err);
      alert("Error uploading file.");
    }
  };

  const handleAction = async (endpoint, payload, successMessage) => {
    if (!uploadedFilePath) return alert("Please upload an audio file first!");

    try {
      const response = await axios.post(`http://localhost:5001/${endpoint}`, payload);
      alert(successMessage);

      // Add file to download list
      setDownloads((prev) => [...prev, { feature: successMessage, filePath: response.data.filePath }]);
    } catch (err) {
      console.error(`Error in ${endpoint}:`, err);
      alert(`Error applying ${endpoint}.`);
    }
  };

  return (
    <div className="audio-upload-container">
      <h1>🎵 Audio Customizer</h1>
      <input type="file" accept="audio/*" onChange={handleFileChange} />
      <button onClick={handleUpload}>Upload Audio</button>

      {uploadedFilePath && (
        <div className="action-buttons">
          <h3>Uploaded Audio: {uploadedFilePath}</h3>
          <button
            onClick={() =>
              handleAction(
                "trim",
                { filePath: uploadedFilePath, start: 30, end: 60 },
                "Trimmed Audio"
              )
            }
          >
            Trim 30s to 60s
          </button>
          <button
            onClick={() =>
              handleAction(
                "change-speed",
                { filePath: uploadedFilePath, speed: 1.5 },
                "Increased Speed"
              )
            }
          >
            Increase Speed (1.5x)
          </button>
          <button
            onClick={() =>
              handleAction(
                "change-pitch",
                { filePath: uploadedFilePath, pitch: 1.2 },
                "Increased Pitch"
              )
            }
          >
            Increase Pitch (1.2x)
          </button>
          <button
            onClick={() =>
              handleAction("reverse", { filePath: uploadedFilePath }, "Reversed Audio")
            }
          >
            Reverse Audio
          </button>
          <button
            onClick={() =>
              handleAction(
                "fade",
                { filePath: uploadedFilePath, fadeInDuration: 3, fadeOutDuration: 3 },
                "Applied Fade"
              )
            }
          >
            Apply Fade
          </button>
          <button
            onClick={() =>
              handleAction(
                "adjust-volume",
                { filePath: uploadedFilePath, volume: 1.5 },
                "Increased Volume"
              )
            }
          >
            Increase Volume (1.5x)
          </button>
          <button
            onClick={() =>
              handleAction("waveform", { filePath: uploadedFilePath }, "Generated Waveform")
            }
          >
            Generate Waveform
          </button>
        </div>
      )}

      {downloads.length > 0 && (
        <div className="download-section">
          <h2>Downloads</h2>
          {downloads.map((file, index) => (
            <div key={index} className="download-item">
              <p>{file.feature}</p>
              <a href={`http://localhost:5001/${file.filePath}`} download>
                Download
              </a>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default AudioUpload;
